def create_web_app(store_path) -> FastAPI:
    """Build a FastAPI app bound to the timesheet store at ``store_path``."""
    app = FastAPI()
    store = TimeStore(store_path)

    def _transition_entry(entry_id: int, target: str):
        try:
            entry = store.get_entry(entry_id)
        except StoreError:
            return _error_page(f"Unknown entry id: {entry_id}", 404)

        try:
            new_status = transition(str(entry["status"]), target)
        except RuleError as exc:
            return _error_page(str(exc), 409)

        store.update_entry(entry_id, status=new_status)
        return RedirectResponse("/", status_code=303)

    @app.get("/", response_class=HTMLResponse)
    def list_entries(week: str | None = None, project: str | None = None) -> HTMLResponse:
        try:
            entries = _filtered_entries(store, week, project)
        except StoreError as exc:
            return _error_page(str(exc), 422)
        body = _filter_form(week, project) + _entries_body(entries)
        return HTMLResponse(page("Timesheet", body))

    @app.post("/entries")
    def add_entry(
        project: str = Form(...),
        date: str = Form(...),
        hours: str = Form(...),
    ):
        try:
            _date.fromisoformat(date)
        except ValueError:
            return _error_page(f"Invalid date: {date}", 422)

        try:
            hours_value = float(hours)
        except ValueError:
            return _error_page(f"Invalid hours: {hours}", 422)

        try:
            day_entries = store.entries_for_date(date)
        except StoreError as exc:
            return _error_page(str(exc), 422)
        day_total = sum(float(entry["hours"]) for entry in day_entries)

        try:
            validate_hours(hours_value, day_total)
        except RuleError as exc:
            return _error_page(str(exc), 422)

        try:
            store.add_entry(project, date, hours_value)
        except StoreError as exc:
            return _error_page(str(exc), 422)

        return RedirectResponse("/", status_code=303)

    @app.post("/entries/{entry_id}/submit")
    def submit_entry(entry_id: int):
        return _transition_entry(entry_id, "submitted")

    @app.post("/entries/{entry_id}/approve")
    def approve_entry(entry_id: int):
        return _transition_entry(entry_id, "approved")

    @app.post("/entries/{entry_id}/reject")
    def reject_entry(entry_id: int):
        return _transition_entry(entry_id, "rejected")

    return app
